  ('dietitian-moex-10944', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列那一項是心臟疾病的初級預防措施？ 定期健康檢查  按時吃藥  少吃高飽和脂肪酸的食物  定期追蹤血壓的情況', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10945', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '進行營養教育之介入研究時，若經費人力不足，下列那一項變通辦法較不影響研究效力（power）？ 配合經費，減少預定樣本人數  改用高危險群個案取代一般民眾 找非專業的人工來進行研究   找其他計算樣本數的公式，重新計算樣本數', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10946', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '為社區老人編寫營養衛教單張中，有一敘述為：「多吃膳食纖維可以抑制膽酸轉變成致癌物」，請問此敘述最不適當 之處為何？ 不切實際    包含兩個以上的觀念 使用醫學術語，易造成溝通不良  內容不正確', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10947', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '關於視聽教材工具中折頁小冊子的功能，下列敘述何者錯誤？ 成本低，可大量印刷    可在短時間內接受簡單易懂的營養知識 避免大家隨看隨丟或不看就丟，應採選擇性的分發  因圖較多文字較少，需要有人從旁加以解釋說明', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10948', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列那一種健康行為理論，特別強調行為意向（behavioral intention）對健康行為的重要性？ 健康信念理論  社會認知論  理性行為論  創新擴散論', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10949', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', 'A市總人口為100,000，A市在過去一年中增加了300名糖尿病患者，根據這項資料可推算出A市糖尿病的： 盛行率  存活率  發生率  自然增加率', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10950', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '選取一組某疾病患者及另一組健康人作為研究對象，令其回憶過去飲食習慣，以探索飲食與疾病的關係，此方法稱為： 社區試驗（community trial）  臨床試驗（clinical trial） 世代研究法（cohort study）   病例對照研究法（case-control study）', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10951', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '以尿糖試紙篩檢糖尿病患者，此試紙的敏感度（sensitivity）是指： 真正有糖尿病的人中，此項檢驗也是陽性的百分率  真正沒有糖尿病的人中，此項檢驗也是陰性的百分率 檢驗結果是陽性的人中，真正有糖尿病的百分率  檢驗結果是陰性的人中，真正沒有糖尿病的百分率', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10952', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列那一種營養介入法是地毯式的（blanket approach）？ 米穀類全面添加鐵質    低收入家庭食物券計畫 禁止校園販售含糖之清涼飲料  供應營養午餐', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-10953', 'dietitian', 'dietitian-moex-093-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '下列那一項營養素是屬於行政院衛生署所公告的需適量攝取之營養宣稱？ 維生素B  鈉  葉酸  維生素C 6', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:57+00:00", "source_pdf_sha1": "bb7efa92b0dc", "answer_pdf_sha1": "d33d11725d39", "source_family": "moex-gov-tw", "moex": {"exam_code": "093120", "c": "112", "s": "5001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "093", "exam_name": "093年第二次專技醫事人員、中醫師、營養師、心理師、呼吸治療師、獸醫人員考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing", "incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
